<template>
    <section class="main-content">
         <loader :is-visible="isLoading"></loader> 
        <div class="row">
            <div class="col-md-12 padding-t_8">
                <div class="theme-primary partition-full">
                    <span class="p-name text-white" v-if="!ticketHeader"> {{ $t('AddTicket') }}</span>
                    <span class="p-name text-white" v-else> {{ $t('EditTicket') }} - {{ headerTicketNumber }}</span>
                    <span class="float-right" v-if="reqModule != 'Asset'">
                        <RouterLink to="/Ticketing/Index" class="p-action-btn text-white float-right">
                            <em class="fa fa-angle-double-left"></em>
                            <br />
                            {{ $t('BacktoList') }}
                        </RouterLink>
                    </span>
                    <span class="float-right" v-if="reqModule == 'Asset'">
                        <RouterLink to="/Asset/MyItems" class="p-action-btn text-white float-right">
                            <em class="fa fa-angle-double-left"></em>
                            <br />
                            {{ $t('BacktoList') }}
                        </RouterLink>
                    </span>
                </div>
            </div>
        </div>
        <div class="border p-3" v-if="isSuccessMessage">
            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12  ticket-thankyou text-center">
                <span class="checksign text-success"><i class="fa fa-check"></i></span>
                <h1 class="mt-4 mb-4">{{ $t('ThankYou') }}</h1>

                <div class="pb-4 ticket-number">
                    <P>{{ saveTicketStatus }}</P>
                    <div
                        style="font-size: 20px;position: relative;background: #fff3cd;padding: 35px 30px; margin: 20px; border: 4px dotted #856404;display: inline-block;color: #856404;">
                        {{ TicketNumber }}</div>
                </div>
            </div>
        </div>
        <Form ref="AddTicket">
            <dynamic-form ref="AddTicketForm" :buttons="buttons" :schema="FormSchema" v-if="!isSuccessMessage">
                <template v-slot:tgslot-comment="{ data }">

                    <ckeditor :editor="editor" @ready="onReady" v-model="data.fieldInfo.value"
                        @input="updateCkeditorModel($event, data)" :class="{ 'is-invalid': data.error != '' }">
                    </ckeditor>
                    <span class="invalid-feedback">{{ data.error }}</span>
                    <input type="hidden" v-model="data.fieldInfo.value" />
                </template>
                <template v-slot:tgslot-addresFields="{ data }" v-if="isForServiceRequest">
                    <div class="row">
                        <div class="col-md-6">
                            <dynamic-form ref="AddTicketForm1" :schema="StaticObj"></dynamic-form>
                        </div>
                        <div class="col-md-6">
                            <ManageMap class="row" mapType="MapBox" mapContainer="AddTicket" :latLng="latLng"
                                :config="config" mapHeight="355px" v-if="isShowMap" @GetAddress="GetAddress">
                            </ManageMap>
                        </div>
                    </div>
                </template>
            </dynamic-form>
        </Form>
        <ManageCategory v-if="isManageCategory" modulename="Ticketing" submodulecode="Ticketing"
            v-bind:callbackfunction="GetDropDownData"></ManageCategory>
        <ManageClient v-if="isManageClient" v-bind:callbackfunction="GetDropDownData"></ManageClient>
    </section>
</template>
<script>
import DataServices from "@/services/DataService";
import ManageMap from './../../components/Common/MapComponent.vue';
import ManageCategory from './DetailsComponent/AddManageCategoryModal.vue';
import ManageClient from '../../components/Modal/modaladdClient.vue'
export default {
    components: {
        ManageMap,
        ManageCategory,
        ManageClient
    },
    data: function () {
        return {
            config: {
                isShowDrawButton: true,
                isShowSearchBox: true
            },
            isDataLoad: false,
            FormSchema: [],
            CountryDDl: '',
            isSuccessMessage: false,
            fileMulitpleData: [],
            isShowMap: true,
            latLng: '',
            UserListDLL: '',
            CountryDDl: '',
            StateDDl: '',
            ticketType: '',
            Latitude: '',
            Longitude: '',
            showTourGuide: true,
            isForServiceRequest: false,
            StaticObj: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "SelectField",
                            label: this.$t('ClientAddress'),
                            name: "AddrTo",
                            value: "",
                            disabled: false,
                            config: {
                                options: [],
                                onChange: this.onChangeDropdown

                            },
                            placeholder: this.$t('Select'),
                            validationRules: "",

                        },
                    ]
                },
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Address'),
                            name: "Address",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('PleaseEnterAddress'),
                            validationRules: { "required": true },
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Country'),
                            name: "country_id",
                            value: "",
                            disabled: true,
                            config: {
                                options: [],
                                onChange: this.GetStateDDL
                            },
                            placeholder: this.$t('Select'),
                            validationRules: "",
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('State'),
                            name: "State",
                            value: "",
                            disabled: true,
                            config: {
                                options: []
                            },
                            placeholder: this.$t('Select'),
                            validationRules: "",
                        },
                        {
                            astype: "TextField",
                            label: this.$t('County'),
                            name: "County",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('PleaseEnterCounty'),
                            validationRules: "",
                        },
                        {
                            astype: "TextField",
                            label: this.$t('City'),
                            name: "City",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('PleaseEnterCityName'),
                            validationRules: "",
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Street'),
                            name: "Street",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('PleaseEnterStreet'),
                            validationRules: "",
                        },
                        {
                            astype: "TextField",
                            label: this.$t('ZipCode'),
                            name: "Zip",
                            value: "",
                            disabled: true,
                            placeholder: this.$t('PleaseEnterZipCode'),
                            validationRules: "",
                        },
                        {
                            astype: "TextField",
                            label: this.$t('NoteAboutAddress'),
                            name: "Notes",
                            value: "",
                            disabled: false,
                            placeholder: this.$t('PleaseEnterDescription'),
                            validationRules: "",
                        },
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",                  
                    class: "btn btn-warning save ancsavedraftticket",
                    text: "<i class='fa fa-save pr-2'></i> Save As Draft",
                    value: "DRAFT",
                    onClick: this.saveForm
                },
                {
                    type: "submit",             
                    class: "btn btn-success save ancsaveuserticket",
                    text: "<i class='fa fa-save pr-2'></i> Submit",
                    onClick: this.saveForm
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i> Cancel",
                    onClick: this.Close
                }
            ],
            isManageCategory: false,
            isManageClient: false,
            AllowedFileType: [],
            ConsumerId:'',
            assignedToId: '',
            channelValue:'',
            editor: this.CLASSIC_EDITOR,
            userType:'',
            reqModule:'',
            isAssetPermission:false,
            ticketHeader : false,
            headerTicketNumber:'',
            isLoading: false,
            removeAttachmentId:[],
            consumerId:0

        }
    },
    created: async function () {
        var vm = this;
        vm.userid = this.GetUserInfo.ID;
        vm.userType = this.GetUserInfo.UserType;
        vm.reqModule = vm.$route.query.reqModule;
        if (!vm.isBlank(vm.$route.params.id) && vm.$route.params.id != "0") {
            let ticket_id = decodeURIComponent(vm.$route.params.id);
            vm.ticketHeader =true;
           await vm.getForm(ticket_id);
        }
        else {
            if (vm.$route.params.id == "0") {
                await vm.getForm(0);
            }
            else {
                vm.$router.push({ name: "add", params: { id: 0 } });
                await vm.getForm(0);
            }
        }
        vm.GetPrivilegeData()
        vm.GetCountryDDL();
    },
    methods: {
        
        GetAddress: function (data) {
            var vueObj = this;
            vueObj.Latitude = '';
            vueObj.Longitude = '';
            var indexValue = data.length - 1;
            let filteredCountry = vueObj.CountryDDl.filter((item) => {
                return item.name === data[indexValue].CompleteAddress.Country.LongName;
            });
            vueObj.StaticObj[1].Data[0].value = data[indexValue].CompleteAddress.FullAddress;
            var filterCountry = filteredCountry == '' ? '' : filteredCountry[0].value;
            vueObj.StaticObj[1].Data[1].value = filterCountry;
            vueObj.GetStateDDL(null, filterCountry);
            setTimeout(function () {
                let filteredState = vueObj.StateDDl.filter((item) => {
                    return item.name === data[indexValue].CompleteAddress.AdministrativeAreaLevel1.LongName;
                });
                var filterState = filteredState == '' ? '' : filteredState[0].value;
                vueObj.StaticObj[1].Data[2].value = filterState;
            }, 1000);
            vueObj.StaticObj[1].Data[3].value = data[indexValue].CompleteAddress.AdministrativeAreaLevel2.LongName;
            vueObj.StaticObj[1].Data[4].value = data[indexValue].CompleteAddress.City.LongName;
            vueObj.StaticObj[1].Data[5].value = data[indexValue].CompleteAddress.AdministrativeAreaLevel3.LongName;
            vueObj.StaticObj[1].Data[6].value = data[indexValue].CompleteAddress.PinCode;
            var dataLat1 = ''; var dataLat2 = ''; var dataLng1 = ''; var dataLng2 = '';
            data[indexValue].LatLng.forEach((item, index) => {
                if (index == 0) {
                    dataLat1 = item.Lat;
                    dataLat2 = item.Lng;
                }
                else {
                    dataLng1 = item.Lat;
                    dataLng2 = item.Lng;
                }
            });
            vueObj.Latitude = dataLng1 + ',' + dataLat2;
            vueObj.Longitude = dataLat1 + ',' + dataLng2;

            vueObj.FormSchema.forEach((group, gi) => {
                group.Data.forEach((field, fi) => {
                    if (group.group_name == "General Information" || group.group_name == "GeneralInformation") {
                        if (field.name == "location_se") {
                            field.value = vueObj.Latitude;
                        }
                        if (field.name == "location_nw") {
                            field.value = vueObj.Longitude;
                        }
                    }
                });
            });
        },
        onChangeDropdown: async function (e) {
            var vm = this;
            var dropName = e.target.name;
            var clientAddressId = '';
            if (dropName == "AddrTo") {
                clientAddressId = e.target.value;
            }
            vm.FormSchema.forEach((group, gi) => {
                group.Data.forEach((field, fi) => {
                    if (field.name == "on_behalf_consumer_id") {
                        let clientid = field.value.value;
                        if (!vm.isBlank(clientid) && clientAddressId != '') {
                            vm.BindAddressUsingClientAdrress(clientid, clientAddressId);
                        }
                    }
                });
            });
        },
        GetCountryDDL: async function (event) {
            var vm = this;
            vm.StaticObj[1].Data[1].config.options = [];
            vm.CountryDDl = '';
            var appendingUrl = `id=&&moduleName=TICKETING&type=${'COUNTRIES'}&search=&refId=`;
            await DataServices.GetDDLDataFSM(appendingUrl).then(function (response) {
                if (response.data) {
                    var json = response.data;
                    vm.CountryDDl = response.data.result.DATA;
                    if (json != null) {
                        response.data.result.DATA.forEach((item, index) => {
                            vm.StaticObj[1].Data[1].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                }
            });
        },
        // GetUserDDLOnBehalf: async function (type) {
        //     var vm = this;
        //     vm.UserListDLL = '';
        //     var url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
        //     await DataServices.GetDDLData(appendingUrl).then(function (response) {
        //         if (response.data) {
        //             var json = response.data;
        //             if (json != null) {
        //                 vm.UserListDLL = response.data.DATA;
        //             }
        //         }
        //     });
        // },
        // GetClientDDLOnBehalf: async function (type) {
        //     var vm = this;
        //     vm.ClientListDLL = '';
        //     var url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
        //     await DataServices.GetDDLData(appendingUrl).then(function (response) {
        //         if (response.data) {
        //             var json = response.data;
        //             if (json != null) {
        //                 vm.ClientListDLL = response.data.DATA;
        //             }
        //         }
        //     });
        // },
        GetStateDDL: async function (event, id) {
            var vm = this;
            var CountryId = 0;
            if (event == null) {
                CountryId = id;
            } else {
                CountryId = event.target.value.toString();
            }
            vm.StaticObj[1].Data[2].config.options = [];
            vm.StateDDl = '';
            var appendingUrl = `id=&&moduleName=TICKETING&type=${'STATE'}&search=&refId=` + CountryId;
            await DataServices.GetDDLDataFSM(appendingUrl).then(function (response) {
                if (response.data) {
                    var json = response.data;
                    vm.StateDDl = response.data.result.DATA;
                    if (json != null) {
                        response.data.result.DATA.forEach((item, index) => {
                            vm.StaticObj[1].Data[2].config.options.push({
                                value: item.value,
                                name: item.name
                            })
                        })
                    }
                }
            });
        },
        BindAddressUsingClientAdrress: async function (clientid, clientAddressId) {
            var vueObj = this;
            vueObj.Latitude = '';
            vueObj.Longitude = '';
            vueObj.latLng = '';
            var url = `id=${clientid}&moduleName=TICKETING&addressId=${clientAddressId}`;
            await DataServices.GetTicketClientAddress(url).then(response => {

                if (response.data.result != null && response.data.result.data.length > 0) {
                    vueObj.StaticObj[1].Data[0].value = response.data.result.data[0].USER_ADDRESS_1;
                    vueObj.StaticObj[1].Data[1].value = response.data.result.data[0].COUNTRY_ID;
                    vueObj.StaticObj[1].Data[2].value = response.data.result.data[0].CT[0].ST[0].STATE_ID;
                    vueObj.StaticObj[1].Data[4].value = response.data.result.data[0].USER_CITY;
                    vueObj.StaticObj[1].Data[6].value = response.data.result.data[0].USER_ZIPCODE;
                    vueObj.StaticObj[1].Data[7].value = response.data.result.data[0].USER_ADDRESS_DESC;
                    vueObj.Latitude = response.data.result.data[0].Latitude + ',' + response.data.result.data[0].Longitude;
                    vueObj.Longitude = response.data.result.data[0].Latitude + ',' + response.data.result.data[0].Longitude;
                    vueObj.FormSchema.forEach((group, gi) => {
                        group.Data.forEach((field, fi) => {
                            if (group.group_name == "General Information" || group.group_name == "GeneralInformation") {
                                if (field.name == "location_se") {
                                    field.value = vueObj.Latitude;
                                }
                                if (field.name == "location_nw") {
                                    field.value = vueObj.Longitude;
                                }
                            }
                        });
                    });
                    var obj = { location_nw: vueObj.Latitude }
                    vueObj.latLng = obj;
                }
            })
        },
        BindAddressInEdit: async function (data) {
            var vueObj = this;
            vueObj.Latitude = '';
            vueObj.Longitude = '';
            vueObj.latLng = '';
            if (data != null) {
                vueObj.StaticObj[1].Data[0].value = data[0].ADDRFROM;
                vueObj.StaticObj[1].Data[1].value = data[0].COUNTRY_ID;
                vueObj.StaticObj[1].Data[2].value = data[0].STATE;
                vueObj.StaticObj[1].Data[4].value = data[0].CITY;
                vueObj.StaticObj[1].Data[3].value = data[0].COUNTY;
                vueObj.StaticObj[1].Data[6].value = data[0].ZIP;
                vueObj.StaticObj[1].Data[5].value = data[0].DIGSTREET;
                vueObj.StaticObj[1].Data[7].value = data[0].NOTES;
                vueObj.Latitude = data[0].LOCATION_NW;
                vueObj.Longitude = data[0].LOCATION_SE;
                vueObj.FormSchema.forEach((group, gi) => {
                    group.Data.forEach((field, fi) => {
                        if (group.group_name == "General Information" || group.group_name == "GeneralInformation") {
                            if (field.name == "location_se") {
                                field.value = vueObj.Latitude;
                            }
                            if (field.name == "location_nw") {
                                field.value = vueObj.Longitude;
                            }
                        }
                    });
                });
                var obj = { location_nw: vueObj.Latitude }
                vueObj.latLng = obj;
            }

        },
        onReady(editor) {
            editor.ui.getEditableElement().parentElement.insertBefore(
                editor.ui.view.toolbar.element,
                editor.ui.getEditableElement()
            );
            let mediaIcon = document.getElementsByClassName('ck-dropdown')[2]
            mediaIcon.remove();
            var divToRemove = document.querySelector('.ck-file-dialog-button');
            divToRemove.remove();
            let ArrowIcon = document.getElementsByClassName('ck ck-button ck-off')[8]
            ArrowIcon.remove();
        },
        onChangeEventForFields: function (x, y, z) {
            let ths = this;
            if (x == "FILL_DEPENDENT") {
                y.config.options = [];
                var url = "";
                if (ths.isDataLoad == false  && y.name == "on_behalf_consumer_id"){
                    let type = (z[0] == "3") ? "USERS" : "CLIENTS";
                    url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
                    DataServices.GetDDLData(url).then(function (response) {
                                var labelKey = (z[0] == "3") ? "Select User" : "Select Client";
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "label", ths.$t(((z[0] == "3") ? "User" : "Client")));
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "placeholder", labelKey);
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "value", ths.ConsumerId);
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.options", response.data != "" ? response.data.DATA : []);
                                if (type == "USERS") {
                                    ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.showAddIcon", false);
                                }
                                if (type == "CLIENTS") {
                                    ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.showAddIcon", true);
                                }
                                ths.$refs.AddTicketForm.UpdateKeyValue();
                    });
                } 

                if (ths.isDataLoad == false  && y.name == "assigned_to"){
                    let type = "TICKET_RESOLVER";
                    url = `id=&moduleName=TICKETING&type=${type}&search=&refId=${z[0]}`;
                    DataServices.GetDDLData(url).then(function (response) {
                        if (response.data) {
                            var json = response.data;
                            if (json != null) {
                                var labelKey = "Select Assigned To";
                                ths.$refs.AddTicketForm.updateProperty("assigned_to", "value", ths.assignedToId);
                                ths.$refs.AddTicketForm.updateProperty("assigned_to", "config.options", response.data.DATA);
                                ths.$refs.AddTicketForm.updateProperty("assigned_to", "label", "Assign To");
                                ths.$refs.AddTicketForm.updateProperty("assigned_to", "placeholder", labelKey);                                
                                ths.$refs.AddTicketForm.UpdateKeyValue();
                            }
                        }
                    });
                } 
                if (ths.isDataLoad == false  && y.name == "asset_related_info_id"){
                    //debugger;
                    let property = ths.$refs.AddTicketForm.getPropertyValue("on_behalf_consumer_id", "value");
                    let onbehalfConsumerId = property ? property.value : null;
                    // let onbehalfConsumer = ths.$refs.AddTicketForm.getPropertyValue("on_behalf_consumer_id", "value").value;
                    // let onbehalfConsumerId = onbehalfConsumer == undefined ? null : onbehalfConsumer;
                    ths.GetProductUniqueName(z[0],onbehalfConsumerId,'onBehalf');
                } 
                
                if (ths.isDataLoad == false  && y.name == "ticket_channel"){
                    let type = "CHANNEL";
                    url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
                    DataServices.GetDDLData(url).then(function (response) {
                        if (response.data) {
                            var json = response.data;
                            if (json != null) {
                                var labelKey = "Select Ticket Channel";
                                ths.$refs.AddTicketForm.updateProperty("ticket_channel", "value", ths.channelValue);
                                ths.$refs.AddTicketForm.updateProperty("ticket_channel", "config.options", response.data.DATA);
                                ths.$refs.AddTicketForm.updateProperty("ticket_channel", "label", "Ticket Channel");
                                ths.$refs.AddTicketForm.updateProperty("ticket_channel", "placeholder", labelKey);                                
                                ths.$refs.AddTicketForm.UpdateKeyValue();
                            }
                        }
                    });
                } 
                
                if (ths.isDataLoad == true && y.name != "on_behalf_consumer_id") {
                   url = `id=&moduleName=TICKETING&type=${y.config.fieldCode}&search=&refId=${z}`;
                   DataServices.GetDDLData(url).then(function (response) {
                    if (response.data) {
                        var json = response.data;
                        if (json != null) {
                            y.config.options = response.data.DATA;
                            ths.$refs.AddTicketForm.UpdateKeyValue();
                        }
                    }
                    });
                }
                // if(ths.isDataLoad == false && y.name =='on_behalf_consumer_id'){
                //     //debugger
                //     //ths.GetClientaddress(null,z.value);
                // } 
            } 
            else {
                if (y.name == "attachment") {
                    ths.GetBase64String(y.value);
                } 
                else if (y.name == "ticket_category_id") {
                    let catOptions = ths.$refs.AddTicketForm.getPropertyValue("ticket_category_id", "config.options")
                    let getSelectedValue = catOptions.filter((x) => { return x.value == y.value })
                    ths.isForServiceRequest = getSelectedValue[0].first_value == "1" ? true : false;
                    if (ths.isForServiceRequest) {
                        ths.FormSchema.forEach(function (g, gi) {
                            if (g.group_name == "Address") {
                                g.visibility = true;
                            }
                        })
                        ths.$refs.AddTicketForm.updateProperty("ticket_for", "value", "2");
                        ths.$refs.AddTicketForm.updateProperty("on_behalf", "value", "4");
                        ths.$refs.AddTicketForm.updateProperty("is_field_service", "value", "1");
                    } else {
                        ths.FormSchema.forEach(function (g, gi) {
                            if (g.group_name == "Address") {
                                g.visibility = false;
                            }
                        })
                        ths.$refs.AddTicketForm.updateProperty("ticket_for", "value", "1");
                        ths.$refs.AddTicketForm.updateProperty("on_behalf", "value", "");
                        ths.$refs.AddTicketForm.updateProperty("is_field_service", "value", "0");
                    }
                }
                else if (y.name == "on_behalf") {
                    let type = (y.value == "3") ? "USERS" : "CLIENTS";
                    var url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
                    DataServices.GetDDLData(url).then(function (response) {
                                var labelKey = (y.value == "3") ? "Select User" : "Select Client";
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "value", "");
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.options", response.data != "" ? response.data.DATA : []);
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "label", ths.$t(((y.value == "3") ? "User" : "Client")));
                                ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "placeholder", labelKey);
                                if (type == "USERS") {
                                    ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.showAddIcon", false);
                                }
                                if (type == "CLIENTS") {
                                    ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "config.showAddIcon", true);
                                }
                                ths.$refs.AddTicketForm.UpdateKeyValue();
                    });
                }
                else if (y.name == "START_DATE") {
                    ths.FormSchema.forEach((group, gi) => {
                        group.Data.forEach((field, fi) => {
                            if (field.name == "END_DATE") {
                                field.value = "";
                                field.config.minDate = x;
                            }
                        });
                    });
                }
                else if (y.name == "SA_Scheduled_StartTime") {
                    ths.FormSchema.forEach((group, gi) => {
                        group.Data.forEach((field, fi) => {
                            if (field.name == "SA_Scheduled_EndTime") {
                                field.config.minDate = x;
                            }
                        });
                    });
                } 
                else if(ths.isDataLoad == false && y.name =='ticket_for' && ths.isAssetPermission == true){
                    if(y.name =='ticket_for' && y.value  == "1" && ths.reqModule == "Asset") {
                        ths.GetAssetProductName(null,'self');
                    }  
                    else if(y.name =='ticket_for' && y.value  == "1") {
                        ths.GetAssetProductName(null,'self');
                    }   
                    else if(y.name =='ticket_for' && y.value  == "2" && ths.reqModule == "Asset"){
                            ths.$refs.AddTicketForm.updateProperty("asset_related_info_id", "disabled", false);
                            ths.$refs.AddTicketForm.updateProperty("product_id", "disabled", false);
                            ths.$refs.AddTicketForm.UpdateKeyValue();
                    }                
                }   
                if(ths.isDataLoad == false && y.name =='on_behalf_consumer_id'){   
                    ths.GetClientaddress(null,z.value);
                    if(ths.isAssetPermission == true){
                        ths.GetAssetProductName(z.value);
                    }
                }   
                if(ths.isDataLoad == false && y.name =='product_id'){  
                    if(y.value == ""){
                        ths.$refs.AddTicketForm.updateProperty("asset_related_info_id", "config.options", []);
                        ths.$refs.AddTicketForm.updateProperty("asset_related_info_id", "value", "");
                        ths.$refs.AddTicketForm.UpdateKeyValue();
                    }
                    else{
                        let property = ths.$refs.AddTicketForm.getPropertyValue("on_behalf_consumer_id", "value");
                        let onbehalfConsumerId = property ? property.value : null;
                         ths.GetProductUniqueName(y.value,onbehalfConsumerId,'onBehalf');
                    }
                }    
            }
        },
        GetAssetProductName: function(id,ticketFor){
            var vm = this;
            vm.$refs.AddTicketForm.updateProperty("product_id", "config.options", []);
            vm.$refs.AddTicketForm.updateProperty("asset_related_info_id", "config.options", []);
            vm.$refs.AddTicketForm.updateProperty("product_id", "value", "");
            vm.$refs.AddTicketForm.updateProperty("asset_related_info_id", "value", "");
            vm.$refs.AddTicketForm.UpdateKeyValue();

            var url='';
            if(id == null){
                url = `id=&moduleName=TICKETING&type=ASSET_PRODUCT_NAME_FOR_TICKET&search=&refId=`;
            }else{
                 url = `id=&moduleName=TICKETING&type=ASSET_PRODUCT_NAME_FOR_TICKET&search=&refId=${id}`;
            }
            DataServices.GetDDLData(url).then(function (response) {
               if (response.data) {
                 var json = response.data;
                    if (json != null) {
                        vm.$refs.AddTicketForm.updateProperty("product_id", "config.options", response.data.DATA);
                        vm.$refs.AddTicketForm.UpdateKeyValue();
                        if(ticketFor =="self"){
                            vm.GetProductUniqueName(vm.$route.query.AssetCatlogueId,null);
                        }
                    }
                }
                else{
                    vm.$refs.AddTicketForm.updateProperty("product_id", "config.options", []);
                    vm.$refs.AddTicketForm.updateProperty("asset_related_info_id", "config.options", []);
                    vm.$refs.AddTicketForm.UpdateKeyValue();
                }
            });
        },
        GetProductUniqueName: function(catalogueId,onBehalfUserId,ticketFor){
            var vm = this;
          
            let type = "PRODUCT_UNIQUE_NAME_BY_CATALOGUE_ID";
            var url='';
            if(onBehalfUserId == null){
                url = `id=${catalogueId}&moduleName=TICKETING&type=${type}&search=&refId=`;
              
            }else{
                url = `id=${catalogueId}&moduleName=TICKETING&type=${type}&search=&refId=${onBehalfUserId}`;
            }
            DataServices.GetDDLData(url).then(function (response) {
            if (response.data) {
