        GetClientaddress: async function (event, id) {
            var vm = this;
            var clientId = 0;
            if (event == null) {
                clientId = id;
            } else {
                clientId = event.target.value.toString();
                vm.clientId = clientId;
            }
            vm.StaticObj[0].Data[0].config.options = [];
            var appendingUrl = `id=&&moduleName=TICKETING&type=${'CLIENT_ADDRESS_LIST_WO'}&search=&refId=` + clientId;
            await DataServices.GetDDLDataFSM(appendingUrl).then(function (response) {
                if (response.data) {
                    var json = response.data;
                    if (json != null) {
                        if (response.data.result.DATA != undefined) {
                            response.data.result.DATA.forEach((item, index) => {
                                vm.StaticObj[0].Data[0].config.options.push({
                                    value: item.value,
                                    name: item.name
                                })
                                if (item.first_value == "1") {
                                    vm.StaticObj[0].Data[0].value = item.value;
                                    vm.BindAddressUsingClientAdrress(clientId, item.value);
                                }
                            })
                            vm.$refs.AddTicketForm.UpdateKeyValue();
                        }
                        else {
                            vm.StaticObj[1].Data[0].value = '';
                            vm.StaticObj[1].Data[1].value = '';
                            vm.StaticObj[1].Data[2].value = '';
                            vm.StaticObj[1].Data[3].value = '';
                            vm.StaticObj[1].Data[4].value = '';
                            vm.StaticObj[1].Data[5].value = '';
                            vm.StaticObj[1].Data[6].value = '';
                        }
                    }
                }
            });
            //vm.GetUtilityDDL(event, id);
        },
        GetBase64String: function (evt) {
            try {
                var vm = this;
                for (var i = 0; i < evt.length; i++) {
                    var f = evt[i];
                    var reader = new FileReader();
                    let fileObj = {};              
                    reader.onload = (function (theFile) {
                        return function (e) {
                            var binaryData = e.target.result;
                            var base64StringEncoded = window.btoa(binaryData);
                            var fileName = f.name;
                            var n = fileName.lastIndexOf(".");
                            var extensionName = fileName.substring(n + 1, fileName.length);
                            vm.fileExt += "." + extensionName;
                            var attachemnetMime = '{"ContentType":"' + f.type + '","Size":"' + f.size + '","Extension":"' + extensionName + '"}';
                            var fileSize = f.size;
                            fileObj.attachement_mime = attachemnetMime,
                            fileObj.fileName = fileName,
                            fileObj.base64String = base64StringEncoded,
                            fileObj.fileSize = f.size,
                            fileObj.contentType = f.type,
                            fileObj.ModuleName = 'TICKETING',
                            fileObj.SubModuleCode = 'TICKETING',
                            fileObj.AttachmentId=''
                            vm.fileMulitpleData.push(fileObj);
                        };
                    })(f);
                    reader.readAsBinaryString(f);
                }
            } catch (ex) {
                console.error("Error processing attachments:", ex);
            }
        },
        Close() {
            this.$router.push({ name: "TicketingList" });
        },
        GetDropDownData: function (type, field, id) {
            var vm = this;
            var url = `id=&moduleName=TICKETING&type=${type}&search=&refId=`;
            DataServices.GetDDLData(url).then(response => {
                field.config.options = [];
                field.value = '';
                if (response.status == 200) {
                    if (type == "TICKET_CATEGORY") {
                        if (!vm.isBlank(response.data.DATA)) {
                            response.data.DATA.forEach((item) => {
                                field.config.options.push({
                                    value: item.value,
                                    name: item.name
                                })
                            })
                        }
                    }
                    if (type == "CLIENTS") {
                        if (!vm.isBlank(response.data.DATA)) {
                            response.data.DATA.forEach((item) => {
                                field.config.options.push({
                                    value: item.value,
                                    name: item.name
                                })
                            })
                        }
                    }
                }
                vm.$refs.AddTicketForm.UpdateKeyValue();
            })
        },
        getForm: async function (id) {
            var ths = this;
            var addressResult = '';
            var attachmentsArray = [];
            let parsedLocalStorage = localStorage.getItem('TALGYEN_NAVBAR_SETTING');
            let selectedLang = "en"; // Default to English
            if(parsedLocalStorage) {
                const settings = JSON.parse(parsedLocalStorage);
                selectedLang = settings.lang.toLowerCase() || "en"; // Use stored language or default to English
            }
            ths.isLoading = true;
            var url = `recordId=${id}&moduleName=Ticketing&subModuleCode=Ticketing&langCode=${selectedLang}`;
            await DataServices.GetDynamicForm(url).then(function (response) {
                if (response != null && response.data != null) {
                    var responseData = response.data.data;
                    var CC_user = response.data.CC_User != "" ? response.data.CC_User[0].cc_user.toString() : ' ';

                    if (response.data.Attachment.length > 0) {
                        response.data.Attachment.forEach(element => {
                              let attachmentData = {
                                attachmentId: element.ticket_attachment_id,
                               attachmentName: element.attachment_name,
                               attachmentPath: element.attachment_path,
                               attachmentDesc: element.attachment_desc
                           };
                           attachmentsArray.push(attachmentData);
                        });
                        
                    }
                    if (response.data.configData.length > 0) {
                        var configResult = response.data.configData;
                        configResult.forEach(function (row) {
                            if (row.CORE_CONFIG_KEY == "TicketDisallowedFileTypes") {
                                ths.AllowedFileType = row.CONFIG_DATA_VALUE;

                            }

                        });
                    }
                    if (response.data.addressData.length > 0) {
                        addressResult = response.data.addressData;

                    }
                    var frmSchma = []
                    frmSchma = ths.$refs.AddTicketForm.ConvertCustomFieldIntoDynamicFormObj(responseData);
                    var TicketCategoryMandatory, TicketProductMandatory;
                    $.each(configResult, $.proxy(function (index1, item) {
                        if (item.CORE_CONFIG_KEY == "TicketCategoryOptionMandatory") {
                            TicketCategoryMandatory = item.CONFIG_DATA_VALUE;
                        }
                        if (item.CORE_CONFIG_KEY == "TicketProductOptionMandatory") {
                            TicketProductMandatory = item.CONFIG_DATA_VALUE;
                        }
                    }, this))
                    frmSchma.forEach((group, gi) => {
                        group.Data.forEach((field, fi) => {
                            if (field.astype == 'RadioField' && ths.$route.params.id == "0") {
                                    var xvalue = '';
                                    field.config.options.forEach((x, i) => {
                                        if (i == 0) {
                                            xvalue = x.value
                                        }
                                    })
                                    field.value = xvalue;
                                }
                            if (field.name == "is_read") {
                                field.value = 0;
                            }
                            if (field.name == "status_id") {
                                if (field.config.options.length > 0) {
                                    field.value = 1111;
                                }
                            }
                            if (field.name == "ticket_number") {
                                ths.headerTicketNumber=  '#'+  field.value;
                            }
                            if(field.astype == "ToggleField"){
                                field.value = field.value=='true'?true:false;
                            }
                            else if (field.name == "ticket_for" && ths.$route.params.id == "0") {
                                field.value = "1";
                            }
                            else if (field.name == "on_behalf" && ths.$route.params.id == "0") {
                                field.value = "4";
                            }
                            else if (field.name == "assigned_to") {
                                ths.assignedToId = field.value;
                                field.visibility = false;
                                field.label = 'Assign To';                               
                            }
                        
                            
                            else if (field.name == "ticket_channel") {
                                ths.channelValue = field.value;                                                              
                            }
                            else if (field.name == "ticket_category_id") {
                                if (TicketCategoryMandatory == "yes") {
                                    field.validationRules.required = true;
                                } else {
                                    field.validationRules.required = false;
                                }
                                if(ths.userType !== 'CL'){
                                    field.config.showAddIcon = true;
                                   field.config.onAddButtonClick = ths.OpenCategoryModal;
                                }
                               
                            }                            
                            else if (field.name == "cc_users") {
                                if(ths.userType !== 'CL'){
                                    field.astype = "MultiSelectField";
                                    field.mode = "tag";
                                    field.value = ((typeof(CC_user) != 'undefined' && CC_user != "undefined") ? CC_user: "");
                                }
                                else{
                                    field.visibility=false;
                                }
                              
                            }
                            else if (field.name == "product_id") {
                                if (TicketProductMandatory == "yes") {
                                    field.validationRules.required = true;
                                } else {
                                    field.validationRules.required = false;
                                }
                            }
                            else if (field.name == "asset_related_info_id") {
                                if(ths.reqModule == "Asset"){
                                    ths.GetProductUniqueName(ths.$route.query.AssetCatlogueId,null);
                                    // field.visibility = true;
                                }
                                else{
                                    // field.visibility = false;
                                }
                                
                            }
                            else if (field.name == "is_field_service" && field.value == "1") {
                                ths.isForServiceRequest = true;

                                ths.BindAddressInEdit(addressResult);
                            }
                            else if (field.name == "on_behalf_consumer_id") {
                                ths.ConsumerId = field.value;
                                //ths.$refs.AddTicketForm.updateProperty("on_behalf_consumer_id", "value", field.value);
                                // ths.$refs.AddTicketForm.UpdateKeyValue();
                                field.config.showAddIcon = true;
                                field.astype = "CustomSelectField";
                                // field.mode = "tag";
                                field.config.onAddButtonClick = ths.OpenClientModal;
                            }
                            else if (group.group_name == "Preferred Time") {
                                if (field.name == "START_DATE" || field.name == "END_DATE") {
                                    field.config.format = "MM/DD/YYYY h:mm A";
                                    field.config.minDate = "";
                                }
                            }

                            else if (field.name == "attachment") {
                                field.showLabel = false;
                                let fileTypeList = ths.AttachmentDisallowedFileType(ths.AllowedFileType);
                                if (fileTypeList != null) {
                                    field.config =
                                    {
                                        maxSize: 5,
                                        reject: fileTypeList,
                                        showSelectedFiles: [],
                                        onDeleteSelectedFiles: ths.onDeleteSelectedFiles,
                                        onClickSelectedFiles: ths.onClickSelectedFiles,
                                        onRemoveFile: ths.onRemoveFile,
                                        showAddIcon: false,
                                        onAddButtonClick: '',
                                        multiple: true
                                    };

                                    if (attachmentsArray.length > 0) {
                                        field.config.showSelectedFiles.push(...attachmentsArray);
                                    }
                                }
                            }
                            field.config.onChange = ths.onChangeEventForFields;
                        })
                    })
                    frmSchma.push(
                        {
                            layoutType: "single",
                            group_name: 'ticketType',
                            visibility: false,
                            Data: [{
                                astype: "SlotField",
                                name: "TicketType",
                                value: "",
                                visibility: false,
                            }]
                        });
                    frmSchma.push({
                        layoutType: "single",
                        group_name: 'Address',
                        visibility: false,
                        Data: [{
                            astype: "SlotField",
                            name: "addresFields",
                            value: "",
                            visibility: true,
                            showLabel: false
                        }]
                    });
                    ths.FormSchema = frmSchma;
                    ths.isLoading = false;
                }
            });
        },
        OpenCategoryModal: function () {
            var vm = this;
            vm.isManageCategory = true;
        },
        OpenClientModal: function () {
            var vm = this;
            vm.isManageClient = true;
        },
        onRemoveFile:function(x,y,z){
            var index = y; 
            if (index >= 0 && index < this.fileMulitpleData.length) {
                this.fileMulitpleData.splice(index, 1);
            }
        },
        onDeleteSelectedFiles: function (item) {
            const attachmentConfig = this.findAttachmentConfig();
            if (attachmentConfig) {
                const index = attachmentConfig.showSelectedFiles.indexOf(item);
                if (index > -1) {
                    attachmentConfig.showSelectedFiles.splice(index, 1);
                }
            }
            let fileObj = { attachmentId: item.attachmentId };
            this.removeAttachmentId.push(fileObj);
        },
        onClickSelectedFiles: function(item)
        {
            var vm = this;
            vm.isLoading = true;
            var param = `filePath=${item.attachmentPath}&fileName=${item.attachmentName}`;
            DataServices.DownloadFile(param).then(function (response) {
                vm.isLoading = false;
                const byteData = response.data;
                const fileURL = `data:${((JSON.parse(item.attachmentDesc)).ContentType)};base64,${byteData}`;
                var fileLink = document.createElement('a');
                fileLink.href = fileURL;
                fileLink.setAttribute('download', item.attachmentName);
                document.body.appendChild(fileLink);
                fileLink.click();
             });
                vm.isLoading = false;
        },
        findAttachmentConfig() {
            for (let item of this.FormSchema) {
                if (item.Data) {
                    for (let dataItem of item.Data) {
                        if (dataItem.label && dataItem.label.toLowerCase().includes('attachment')) {
                            return dataItem.config;
                        }
                    }
                }
            }
            return null;
        },
        saveForm: function (btnType) {
            var ths = this;
            ths.$refs.AddTicket.validate().then(result => {
                if (result) {
                    ths.buttons[0].class += " disabled";
                    ths.buttons[1].class += " disabled";
                    if (btnType.value == "DRAFT") {
                        ths.FormSchema.forEach((group, gi) => {
                            group.Data.forEach((field, fi) => {
                                if (group.group_name == "ticketType") {
                                    if (field.name == "TicketType") {
                                        field.value = 'DRAFT';
                                    }
                                }
                            });
                        });
                        ths.ticketType = 'DRAFT';
                    }
                    ths.isLoading = true;
                    var CustomFieldArray = ths.$refs.AddTicketForm.ConvertDynamicFormObjToCustomFieldObj(ths.FormSchema);
                    var CustomFieldArrayStatic = ths.$refs.AddTicketForm.ConvertDynamicFormObjToCustomFieldObj(ths.StaticObj);
                    CustomFieldArray.forEach((x) => {
                        if (x.field_name == "on_behalf_consumer_id") {
                            if (!ths.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if (x.field_name == "cc_users") {   
                                if (!ths.isBlank(x.field_value) && x.field_value.length > 0) {
                                    var CCUsers = '';
                                    x.field_value.forEach((row) => {
                                        CCUsers += row.value + ', ';
                                    });
                                    CCUsers = CCUsers.slice(0, -2);
                                    x.field_value = CCUsers;
                                }
                        }
                        if (x.field_name == "weekly") {
                            if (!ths.isBlank(x.field_value)) {
                                x.field_value = x.field_value.value;
                            }
                        }
                        if (x.field_name == "SA_Scheduled_StartTime") {
                            if (x.field_value == "") {
                                x.field_value = null;
                            } else {
                                x.field_value = x.field_value;
                            }
                        }
                        if (x.field_name == "SA_Scheduled_EndTime") {
                            if (x.field_value == "") {
                                x.field_value = null;
                            } else {
                                x.field_value = x.field_value;
                            }
                        }
                    })
                    CustomFieldArrayStatic.forEach((x) => {
                        CustomFieldArray.push(x);
                    });
                   if(ths.fileMulitpleData.length > 0){
                        var commaSeparatedIds = ths.removeAttachmentId.length > 0 ? ths.removeAttachmentId.map(item => item.attachmentId).join(','): '';
                        ths.fileMulitpleData[0].AttachmentId = commaSeparatedIds;
                     }
                    var obj = {
                        data: CustomFieldArray,
                        moduleCode: "Ticketing",
                        subModuleCode: "Ticketing",
                        attachmentData: ths.fileMulitpleData.length > 0 ? ths.fileMulitpleData : null
                    }
                    DataServices.Create(JSON.stringify(obj)).then(function (response) {
                        ths.isLoading = false;
                        if (response != null && response.data != null && response.data[0].Status == "Success") {
                            ths.TicketNumber = JSON.parse(response.data[0].Value.OTHER_DATA).TICKET_NUMBER;
                            ths.isSuccessMessage = true;
                            if (ths.ticketType == 'DRAFT') {
                                // ths.ShowAlert(ths.$t("DraftSuccess", [ths.$t("Ticket")]), "success", true, ths.$t("Alert"));
                                ths.saveTicketStatus = ths.$t("TicketDraftSubmitStatus");
                            }
                            else 
                            {
                                // ths.ShowAlert(ths.$t("AddedSuccess", [ths.$t("Ticket")]), "success", true, ths.$t("Alert"));
                                ths.saveTicketStatus = ths.$t("TicketSubmitStatus");
                            }
                            ths.showTourGuide = false;
                        } else {
                            ths.ShowAlert(ths.$t("ErrorWhileSaving", [ths.$t("Ticket")]), "danger", true, ths.$t("Alert"));
                            ths.buttons[0].class = "btn btn-warning";
                            ths.buttons[1].class = "btn btn-success";
                            
                            ths.isSuccessMessage = false;
                        }
                    })
                }
            })
        },
        updateCkeditorModel: function (e, x) {
            x.fieldInfo.value = e;
        },
        GetPrivilegeData: async function () {
            var vm = this;
            var param = 'controller=Asset&action=MyItems';
            await DataServices.CheckPrivilege(param).then(function (response) {
                if (response.data) {
                    vm.isAssetPermission=true;
                    vm.$refs.AddTicketForm.updateProperty("product_id", "visibility", true);
                    vm.$refs.AddTicketForm.updateProperty("asset_related_info_id", "visibility", true);
                    vm.$refs.AddTicketForm.UpdateKeyValue();
                }
                else { 
                    vm.isAssetPermission=false;
                    vm.$refs.AddTicketForm.updateProperty("product_id", "visibility", false);
                    vm.$refs.AddTicketForm.updateProperty("asset_related_info_id", "visibility", false);
                    vm.$refs.AddTicketForm.UpdateKeyValue();
                 }
            })
        }
    }
}
